INSERT INTO vendor_contract_documents (id, version, title, body_html, body_sha256, effective_from, retired_at, created_by, created_at) VALUES ('vcd_bp_v1', 1, 'Vendor Operating Agreement (boilerplate v1)', '<h2>Vendor Operating Agreement &mdash; [AIR ACTION SPORTS EVENT]</h2><p><strong>Parties.</strong> This agreement is between [VENDOR COMPANY LEGAL NAME] (&ldquo;Vendor&rdquo;) and Air Action Sports LLC (&ldquo;Organizer&rdquo;), effective on the date Vendor countersigns below.</p><h3>1. Services</h3><p>Vendor will provide the services described in the package overview delivered to Vendor through the Air Action Sports vendor portal (the &ldquo;Package&rdquo;) at the event identified in that Package. Vendor is an independent contractor and not an employee, agent, or partner of Organizer.</p><h3>2. Insurance</h3><p>Vendor will maintain general liability insurance with minimum coverage of [$1,000,000] per occurrence and [$2,000,000] aggregate. Vendor will upload a current Certificate of Insurance (COI) naming Air Action Sports LLC as an additional insured before arriving on site. Vendor will not be permitted on site without current coverage on file.</p><h3>3. Site rules</h3><p>Vendor will comply with all Organizer and landowner safety rules at all times, including mandatory eye protection in any designated field-of-play area, FPS limits, and marshal instructions. Vendor will keep vehicles only in designated load-in and parking areas and will not block emergency lanes.</p><h3>4. Indemnification</h3><p>Vendor will indemnify and hold harmless Organizer, its owners, employees, and the landowner from and against any claim arising out of Vendor&rsquo;s services, products, employees, or equipment, except to the extent caused by Organizer&rsquo;s gross negligence or willful misconduct.</p><h3>5. Payment</h3><p>[Describe payment terms here. Examples: &ldquo;Vendor will be paid $[AMOUNT] on the day of the event by check.&rdquo; or &ldquo;Vendor pays Organizer a vendor fee of $[AMOUNT] due at load-in.&rdquo; Delete this section if no money changes hands.]</p><h3>6. Cancellation</h3><p>Either party may cancel this engagement up to [14] days before the event without penalty. Cancellation within [14] days may require the cancelling party to reimburse documented out-of-pocket costs the other party cannot mitigate.</p><h3>7. Force majeure</h3><p>Neither party is liable for failure to perform due to causes beyond reasonable control, including weather, acts of government, fire, or public-health orders.</p><h3>8. Intellectual property &amp; likeness</h3><p>Vendor grants Organizer a non-exclusive license to use Vendor&rsquo;s company name, logo, and promotional photography in event marketing and post-event recaps. Vendor retains all other rights in its brand.</p><h3>9. Governing law</h3><p>This agreement is governed by the laws of the State of [STATE], without regard to conflict-of-laws principles. Any dispute will be resolved in the state or federal courts located in [COUNTY], [STATE].</p><h3>10. Entire agreement</h3><p>This document, together with the Package delivered to Vendor through the vendor portal, is the complete agreement between the parties and supersedes any prior discussions. Changes must be made by a superseding version executed by both parties.</p><hr/><p style="font-size:13px;color:#666"><strong>Signer attestation.</strong> By typing your full legal name and submitting the signature form below, you confirm: (a) you are authorized to sign on behalf of Vendor; (b) you intend your typed name to be your electronic signature on this agreement; (c) you consent to contract electronically and to receive records of this agreement in electronic form.</p>
', '8b06fdcfbedecfb5bc2f727489fbe3c8549c604c6907d5aea8f790437f581faa', (strftime('%s','now')*1000), NULL, NULL, (strftime('%s','now')*1000));
